var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"움직이지 마세요. 릴리. 더 이상은 무리입니다.","JPN":"動かないでください、リリー。これ以上は無理です。","ENG":"Don't move, Lily. You mustn't push yourself any harder.","TWN":"不要動，莉莉。你輸了。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_1"},{"id":"L4_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이...... 더러운 배신자......!","JPN":"この……汚らわしい裏切り者……！","ENG":"You... filthy traitor!","TWN":"你這個……骯髒的叛徒……！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_1"},{"id":"L5_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 몸은 분명 마스터께서 주신 선물일 텐데......","JPN":"その身体はマスターから授かった贈り物なのに……","ENG":"That body must be a gift to you from the Master...","TWN":"你的身體是主人賜予的禮物……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_2"},{"id":"L6_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런 걸 자기 좋을 대로 쓰다니......! 부끄럽지도 않나요?","JPN":"それを勝手に使うなんて……！　この恥知らずめ！","ENG":"How could you use it as you please? Don't you have any shame?","TWN":"怎麼可以如此亂用……！難道你不覺得羞愧嗎？"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_3"},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 몸은 선물이 아니에요.","JPN":"この身体は贈り物ではありません。","ENG":"This body is not a gift.","TWN":"這個身體不是禮物。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_2"},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아픔도 다른 무엇도 못 느끼고, 마스터의 뜻대로 쓰고 버리는 도구에 불과하죠.","JPN":"痛みも何も感じることができない、マスターの意思によって使われ、捨てられる道具にすぎません。","ENG":"It's merely an expendable tool for the Master, unable to feel pain, or anything else for that matter.","TWN":"是一個不能感受到疼痛和其他一切，按照主人的意願隨時可以拋棄的棋子罷了。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_3"},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래서......","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_4"},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래서 그게 뭐 어쨌다는 거야?","JPN":"だからそれがどうしたというの？","ENG":"So what?","TWN":"所以呢？那又怎樣？"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_5"},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"당신이 나한테 가르쳤어. 우리는 마스터가 정원에 기르는 꽃이라고.","JPN":"あなたは私に教えてくれた。私たちはマスターが庭園で育てる花だと。","ENG":"You were the one who taught me that we are the flowers in the Master's garden.","TWN":"是你告訴我，說我們是主人庭院裡的花朵。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_6"},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"주인이 바라는 대로 아름답게 자라서, 주인만을 바라보면 된다고......!","JPN":"主の望みどおり美しく育ち、主だけに忠誠を誓えばいいと……！","ENG":"That all we need to do is grow beautifully and look to our Master!","TWN":"長成主人所喜歡的模樣，盡心侍奉主人就好……！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_7"},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런 당신이 이제 와서 그딴 식으로 마스터를 비난할 수 있어?!","JPN":"なのに今更そんな風にマスターを非難するなんて！","ENG":"How can you now condemn the Master like that?","TWN":"你覺得這樣的你，現在有資格指責主人嗎？！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_8"},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신에게 올바른 세상에 대해 가르쳐 주지 못한 건 미안하게 생각해요.","JPN":"あなたに正しい生き方を教えられなかったことについては申し訳なく思います。","ENG":"I'm sorry that I never taught you how the real world works.","TWN":"我很抱歉我沒能教你正確的世界觀。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_4"},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신이 눈앞에서 다른 메이드들에게 부모님이 살해당할 때 막지 못한 것도.","JPN":"あなたの目の前であなたの両親が他のメイドたちに殺された時に止められなかったことも。","ENG":"And I'm sorry that I failed to stop the other maids from murdering your parents right in front of you.","TWN":"還有其他女僕當著你的面殺害你父母的時候，我也沒能及時阻止。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_5"},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 릴리, 기억을 잃었을 때도 저는 당신을 지키려 했다는 사실만은 잊지 않았어요.","JPN":"しかしリリー、記憶を失った時も私はあなたを守ろうとした事実だけは忘れていませんでした。","ENG":"But Lily... Even when I lost my memories, I still remembered that I had tried to protect you.","TWN":"但是莉莉，即使我失去了記憶，卻從來沒有忘記要守護你。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_6"},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제게...... 당신은 그만큼 소중한 존재였습니다.","JPN":"私にとって……あなたはそれぐらい大切な存在でした。","ENG":"You were that precious to me.","TWN":"對我來說……你是很重要的。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_7"},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그러니 뒤늦게라도......","JPN":"だから遅くなったとしても……","ENG":"That's why I tried to protect you even when it was too late...","TWN":"所以，雖然為時已晚……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_8"},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아니, 더 늦기 전에 지키려 했던 겁니다.","JPN":"いえ、手遅れになる前に守ろうとしたのです。","ENG":"Or rather, before it was too late.","TWN":"不，是想在更晚之前拉回你。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_9"},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모네를 구출해서, 당신이 저처럼 손을 더럽히지 않을 수 있도록 말이에요.","JPN":"モネを救出して、あなたが私のように手を汚してしまわないように。","ENG":"By rescuing Mone, so that you wouldn't have to dirty your hands like I did.","TWN":"我要救出莫妮，不能讓你像我這般髒了自己的雙手。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_10"},{"id":"L31_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......죽여.","JPN":"……殺せ。","ENG":"Just kill me.","TWN":"……殺了我吧。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_9"},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"당신을 솎아내는 데 실패한 이상, 더는 마스터를 모실 자격이 없어.","JPN":"あなたの間引きに失敗した以上、これ以上マスターに仕える資格はない。","ENG":"Now that I've failed to pluck you out, I am no longer worthy of serving the Master.","TWN":"我沒能除掉你，就再也沒有資格侍奉主人。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_10"},{"id":"L34_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그러니 죽여.","JPN":"だから、殺せ。","ENG":"So just kill me now.","TWN":"所以你還是殺了我吧。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_11"},{"id":"L35_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이 자리에서 목숨을 바쳐서라도...... 배신자인 당신과 다르다는 사실을 마스터께 인정 받겠어.","JPN":"この場で命を捧げることで……裏切り者のあなたとは違うと、マスターに認めてもらう。","ENG":"Even if I must give my life here to prove it... I must earn the Master's recognition that I am different from a traitor like you.","TWN":"我哪怕死在這裡……也要向主人證明，我和你這個叛徒不一樣。"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_12"},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"릴리. 저는......","JPN":"リリー、私は……","ENG":"Lily, I...","TWN":"莉莉，我……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_11"},{"id":"L40_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어차피 날 혼자 내버려 두고 갔던 주제에......!","JPN":"私を置き去りにして消えたくせに……！","ENG":"You left me all by myself anyway!","TWN":"你不是拋棄我頭都不回地走了嗎……！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_13"},{"id":"L41_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이제 와서 그딴 사탕발림으로 속이겠다고!","JPN":"今になってそんな口先で騙そうとしても無駄だ！","ENG":"Don't you try to lure me with your sugar-coated words now!","TWN":"現在休想用那些甜言蜜語騙我！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_14"},{"id":"L42_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어째서야! 모두가 당신처럼 훌륭한 메이드장은 없다고 했어!","JPN":"どうして！　みんなあなたのような立派なメイド長は他にいないと言ってた！","ENG":"Why? Everyone said there was no greater Chief Maid than you!","TWN":"大家都說你是最優秀的女僕長，世上再無他人會如你這般！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_15"},{"id":"L43_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"당신을 따라다닐 때 다들 비웃었어!","JPN":"あなたについていた時だってみんなに笑われたの！","ENG":"They all scoffed at me when I followed you around!","TWN":"我跟著你的時候受到了無數次嘲諷！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_16"},{"id":"L44_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저런 비실비실하고 기분 나쁜 꼬마를 메이드장이 가르치는 게 가당키나 하냐면서!","JPN":"あんなガリガリで気持ち悪いガキをメイド長が直接面倒見るなんて有り得ないって！","ENG":"They said it was ridiculous that the Chief Maid was teaching a weak little freak like me!","TWN":"大家都說堂堂女僕長，怎麼可以去教一個弱不禁風的小孩子！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_17"},{"id":"L45_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런데도...... 당신 같은 사람이 되고 싶어서 끝까지 따랐는데......!","JPN":"それでも……あなたのような人になりたくて最後まで慕っていたのに……！","ENG":"But even then... I followed you till the very end because I wanted to be like you!","TWN":"但是……為了成為像你這樣的人，我心甘情願地跟著你……！"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_C_MASK_IN_TRAILER_18"},{"id":"L46_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"언제까지 살려 둘 생각이니? 저렇게 간절히 애원하는 아이를?","JPN":"あんなに切実に死を求める子を、いつまで生かしておく気なの？　","ENG":"Oh, come on. Give the child what she wants already. She's begging so dearly.","TWN":"你到底想什麼時候動手？沒看到她在苦苦哀求你嗎？"},"stage":{"bg":"SS_MAID_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 목소리는......","JPN":"この声は……","ENG":"This voice...","TWN":"這聲音是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"못 본 사이 많이 야위었구나.","JPN":"しばらく会わない間にずいぶんとやつれてしまったわね。","ENG":"You've grown so thin since I saw you last.","TWN":"好久不見，你瘦了許多。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L3_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"베로니카.","JPN":"ベロニカ。","ENG":"Veronica.","TWN":"貝洛妮卡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};